package com.faceAI.demo.SysCamera.addFace;

import android.content.Context;
import android.graphics.Bitmap;
import android.util.Log;

import androidx.annotation.NonNull;

import com.ai.face.faceSearch.search.Image2FaceFeature;

/**
 * 演示通过Base64人脸图提取特征值
 * Image2FaceFeature.getFaceFeatureByBitmap /getFaceFeatureByBase64
 */
public class AddFaceByImageTestDemo {

    public static void addFaceByImageFunc(Context context, String base64, String faceID){
        Image2FaceFeature.getInstance(context).getFaceFeatureByBase64(base64Test, faceID, new Image2FaceFeature.Callback() {
            @Override
            public void onSuccess(@NonNull Bitmap bitmap, @NonNull String faceID, @NonNull String faceFeature) {
                Log.d("AddFaceByImage","faceFeature: "+faceFeature);
            }

            @Override
            public void onFailed(@NonNull String msg) {

            }
        });
    }
    public static String base64Test = "data:image/jpeg;base64,";
}
